using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerToolType]
public class WeatherTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    // Constructor-injected: the MCP SDK resolves this from the DI container
    // each time a tool in this class is invoked.
    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await client.GetFromJsonAsync<WeatherResponse>(url);

        if (response?.Current is null)
            return "No weather data available.";

        var c = response.Current;
        return $"Temperature: {c.Temperature}°C, Wind: {c.WindSpeed} km/h";
    }

    [McpServerTool, Description("Look up coordinates for a city name using geocoding.")]
    public async Task<string> GeocodeCityName(
        [Description("City name to look up")] string city)
    {
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/search?name={Uri.EscapeDataString(city)}&count=1";

        var response = await client.GetFromJsonAsync<GeocodeResponse>(url);

        if (response?.Results is not [var first, ..])
            return $"No results found for '{city}'.";

        return $"{first.Name}: lat={first.Latitude}, lon={first.Longitude} ({first.Country})";
    }
}

// --- JSON response models ---

internal sealed class WeatherResponse
{
    [JsonPropertyName("current")]
    public CurrentWeather? Current { get; set; }
}

internal sealed class CurrentWeather
{
    [JsonPropertyName("temperature_2m")]
    public double Temperature { get; set; }

    [JsonPropertyName("wind_speed_10m")]
    public double WindSpeed { get; set; }
}

internal sealed class GeocodeResponse
{
    [JsonPropertyName("results")]
    public List<GeocodeResult>? Results { get; set; }
}

internal sealed class GeocodeResult
{
    [JsonPropertyName("name")]
    public string Name { get; set; } = "";

    [JsonPropertyName("latitude")]
    public double Latitude { get; set; }

    [JsonPropertyName("longitude")]
    public double Longitude { get; set; }

    [JsonPropertyName("country")]
    public string Country { get; set; } = "";
}

